FEATURE UNDER TEST:

```typescript
// services/summarizer.ts

export interface SummaryResult {
  summary: string;
  keyTopics: string[];
  originalLength: number;
  summaryLength: number;
  compressionRatio: number;
  model: string;
  latencyMs: number;
}

export async function summarizeContent(
  content: string,
  options: SummaryOptions = {}
): Promise<SummaryResult> {
  // Validate input
  if (content.length < 100) {
    throw new Error('Content too short to summarize');
  }

  // Call AI API
  const response = await anthropic.messages.create({
    model: options.model ?? 'claude-3-haiku-20240307',
    max_tokens: options.maxLength ?? 200,
    messages: [{
      role: 'user',
      content: `Summarize this text in 2-3 sentences. Extract key topics.\n\n${content}`,
    }],
  });

  // Parse and validate response
  const parsed = parseAIResponse(response);

  // Quality checks
  if (parsed.summary.length > content.length * 0.5) {
    throw new Error('Summary too long');
  }

  return {
    summary: parsed.summary,
    keyTopics: parsed.keyTopics,
    originalLength: content.length,
    summaryLength: parsed.summary.length,
    compressionRatio: parsed.summary.length / content.length,
    model: response.model,
    latencyMs: response.latency,
  };
}
```

