LAYER 1: DETERMINISTIC INTEGRATION TESTS

```typescript
import { describe, it, expect, vi } from 'vitest';
import { summarizeContent } from './summarizer';
import * as anthropic from '@anthropic-ai/sdk';

vi.mock('@anthropic-ai/sdk');

describe('Summarizer Integration', () => {
  describe('Input Validation', () => {
    it('rejects content under 100 characters', async () => {
      await expect(summarizeContent('Short text'))
        .rejects.toThrow('Content too short');
    });

    it('accepts content over 100 characters', async () => {
      const mockResponse = createMockResponse('Summary text', ['topic1']);
      vi.mocked(anthropic.messages.create).mockResolvedValue(mockResponse);

      const longContent = 'A'.repeat(150);
      await expect(summarizeContent(longContent)).resolves.toBeDefined();
    });
  });

  describe('API Interaction', () => {
    it('calls Claude API with correct parameters', async () => {
      const mockResponse = createMockResponse('Summary', ['topic']);
      vi.mocked(anthropic.messages.create).mockResolvedValue(mockResponse);

      const content = 'A'.repeat(200);
      await summarizeContent(content, { model: 'claude-3-opus' });

      expect(anthropic.messages.create).toHaveBeenCalledWith(
        expect.objectContaining({
          model: 'claude-3-opus',
          messages: expect.arrayContaining([
            expect.objectContaining({
              content: expect.stringContaining(content),
            }),
          ]),
        })
      );
    });
  });

  describe('Quality Threshold Enforcement', () => {
    it('rejects summary longer than 50% of original', async () => {
      // Summary is 60% of original length
      const mockResponse = createMockResponse('A'.repeat(120), ['topic']);
      vi.mocked(anthropic.messages.create).mockResolvedValue(mockResponse);

      const content = 'A'.repeat(200);
      await expect(summarizeContent(content))
        .rejects.toThrow('Summary too long');
    });
  });

  describe('Error Handling', () => {
    it('handles rate limit errors with retry info', async () => {
      vi.mocked(anthropic.messages.create).mockRejectedValue(
        new Error('rate_limit_exceeded')
      );

      await expect(summarizeContent('A'.repeat(200)))
        .rejects.toThrow('rate_limit');
    });

    it('handles timeout errors', async () => {
      vi.mocked(anthropic.messages.create).mockRejectedValue(
        new Error('Request timeout')
      );

      await expect(summarizeContent('A'.repeat(200)))
        .rejects.toThrow('timeout');
    });

    it('handles malformed AI response', async () => {
      const badResponse = { content: [{ type: 'image' }] };  // Expected text
      vi.mocked(anthropic.messages.create).mockResolvedValue(badResponse);

      await expect(summarizeContent('A'.repeat(200)))
        .rejects.toThrow('Invalid response format');
    });
  });
});
```

