LAYER 3: QUALITY ASSERTIONS (Property-Based)

```typescript
describe('Summarizer Quality (Live AI)', () => {
  // Use real AI for quality tests, but only in CI with dedicated test budget
  const testContent = `
    Artificial intelligence is transforming industries worldwide.
    From healthcare to finance, AI applications are becoming ubiquitous.
    Machine learning models can now diagnose diseases, predict market trends,
    and automate complex workflows. However, ethical concerns remain about
    bias, privacy, and job displacement. Researchers are working on
    responsible AI frameworks to address these challenges.
  `;

  it('produces summary shorter than original', async () => {
    const result = await summarizeContent(testContent);
    expect(result.summaryLength).toBeLessThan(result.originalLength);
    expect(result.compressionRatio).toBeLessThan(0.5);
  });

  it('extracts relevant key topics', async () => {
    const result = await summarizeContent(testContent);

    // At least one topic should relate to content
    const expectedTopicPatterns = [
      /artificial intelligence/i,
      /ai/i,
      /machine learning/i,
      /healthcare/i,
      /ethics/i,
    ];

    const topicsText = result.keyTopics.join(' ').toLowerCase();
    const matchingTopics = expectedTopicPatterns.filter(
      pattern => pattern.test(topicsText) || pattern.test(result.summary.toLowerCase())
    );

    expect(matchingTopics.length).toBeGreaterThanOrEqual(2);
  });

  it('does not hallucinate facts', async () => {
    const result = await summarizeContent(testContent);

    // Summary should not mention things not in original
    const hallucinations = [
      /specific company names not in original/i,
      /specific dates not in original/i,
      /statistics not in original/i,
    ];

    hallucinations.forEach(pattern => {
      expect(result.summary).not.toMatch(pattern);
    });
  });

  it('produces grammatically correct output', async () => {
    const result = await summarizeContent(testContent);

    // Basic grammar checks
    expect(result.summary).toMatch(/^[A-Z]/);  // Starts with capital
    expect(result.summary).toMatch(/[.!?]$/);  // Ends with punctuation
    expect(result.summary.split(/[.!?]/).filter(Boolean).length).toBeGreaterThan(0);  // Has sentences
  });
});
```

