LAYER 4: GOLDEN TESTS (Regression Detection)

```typescript
describe('Summarizer Regression', () => {
  const goldenInputs = [
    {
      name: 'tech_article',
      content: loadFixture('tech_article.txt'),
      expectedTopicsSubset: ['technology', 'innovation'],
      expectedLengthRange: [50, 200],
    },
    {
      name: 'news_story',
      content: loadFixture('news_story.txt'),
      expectedTopicsSubset: ['news', 'event'],
      expectedLengthRange: [40, 150],
    },
  ];

  goldenInputs.forEach(({ name, content, expectedTopicsSubset, expectedLengthRange }) => {
    it(`produces consistent output for ${name}`, async () => {
      const result = await summarizeContent(content);

      // Length within expected range
      expect(result.summaryLength).toBeGreaterThanOrEqual(expectedLengthRange[0]);
      expect(result.summaryLength).toBeLessThanOrEqual(expectedLengthRange[1]);

      // Contains expected topic subset
      const topicsLower = result.keyTopics.map(t => t.toLowerCase());
      expectedTopicsSubset.forEach(topic => {
        expect(topicsLower.some(t => t.includes(topic))).toBe(true);
      });

      // Optional: Update snapshots with: npm test -- -u
      expect(result).toMatchSnapshot({
        summary: expect.any(String),  // Ignore exact text
        latencyMs: expect.any(Number),  // Ignore timing
      });
    });
  });
});
```

